import{_ as t,a,b as l,c as o}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as i,o as d,c as n,a2 as s}from"./chunks/framework.DnrXFDHb.js";const C=JSON.parse('{"title":"新增 Google Drive 渠道","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/upload/google-drive.md","filePath":"zh-TW/upload/google-drive.md","lastUpdated":1781962217000}'),r={name:"zh-TW/upload/google-drive.md"};function c(p,e,h,g,u,b){return d(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="新增-google-drive-渠道" tabindex="-1">新增 Google Drive 渠道 <a class="header-anchor" href="#新增-google-drive-渠道" aria-label="Permalink to &quot;新增 Google Drive 渠道&quot;">​</a></h1><h2 id="新增前要準備什麼" tabindex="-1">新增前要準備什麼 <a class="header-anchor" href="#新增前要準備什麼" aria-label="Permalink to &quot;新增前要準備什麼&quot;">​</a></h2><table tabindex="0"><thead><tr><th>需要準備</th><th>用途</th></tr></thead><tbody><tr><td>Google 帳號</td><td>登入 Google Cloud 並授權 Google Drive</td></tr><tr><td>Google Cloud 專案</td><td>啟用 Drive API、建立 OAuth 2.0 憑證</td></tr><tr><td>OAuth 2.0 Client</td><td>取得 <code>Client ID</code>、<code>Client Secret</code> 和 <code>Refresh Token</code></td></tr><tr><td>目前 ImgBed 網域</td><td>設定授權回呼網址，必須和實際使用網域一致</td></tr></tbody></table><h2 id="新增步驟" tabindex="-1">新增步驟 <a class="header-anchor" href="#新增步驟" aria-label="Permalink to &quot;新增步驟&quot;">​</a></h2><h3 id="第一步-啟用-google-drive-api" tabindex="-1">第一步：啟用 Google Drive API <a class="header-anchor" href="#第一步-啟用-google-drive-api" aria-label="Permalink to &quot;第一步：啟用 Google Drive API&quot;">​</a></h3><ol><li>打開 Google Cloud Console。</li><li>建立新專案，或選擇既有專案。</li><li>進入 <code>APIs &amp; Services</code>。</li><li>點 <code>Enable APIs and Services</code>。</li><li>搜尋 <code>Google Drive API</code>。</li><li>進入後啟用。</li></ol><h3 id="第二步-設定-oauth-同意畫面" tabindex="-1">第二步：設定 OAuth 同意畫面 <a class="header-anchor" href="#第二步-設定-oauth-同意畫面" aria-label="Permalink to &quot;第二步：設定 OAuth 同意畫面&quot;">​</a></h3><ol><li>進入 <code>Google Auth Platform</code>。</li><li>先完成 <code>Branding</code> 的基本資訊，例如應用名稱、支援信箱、開發者聯絡信箱。</li><li>進入 <code>Audience</code>。</li><li>大多數個人自架情境選 <code>External</code> 即可。</li><li>如果選 <code>External</code>，把你要授權的 Google 帳號加到 <code>Test users</code>。</li><li>進入 <code>Data Access</code>。</li><li>加入 Google Drive 權限。</li></ol><h3 id="第三步-建立-oauth-2-0-client" tabindex="-1">第三步：建立 OAuth 2.0 Client <a class="header-anchor" href="#第三步-建立-oauth-2-0-client" aria-label="Permalink to &quot;第三步：建立 OAuth 2.0 Client&quot;">​</a></h3><ol><li>在 <code>Google Auth Platform</code> 打開 <code>Clients</code>。</li><li>建立新的 Client。</li><li>應用程式類型選 <code>Web application</code>。</li><li>取一個好辨識的名稱。</li><li>Authorized JavaScript origins 填你的 ImgBed 網址，例如：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com</span></span></code></pre></div><ol start="6"><li>Authorized redirect URIs 填：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+t+'" alt="建立 OAuth Client" loading="lazy"></p><p><img src="'+a+'" alt="填寫 ImgBed 網域與回呼網址" loading="lazy"></p><p>建立完成後，複製：</p><table tabindex="0"><thead><tr><th>產生結果</th><th>ImgBed 欄位</th></tr></thead><tbody><tr><td>Client ID</td><td><code>Client ID</code></td></tr><tr><td>Client Secret</td><td><code>Client Secret</code></td></tr></tbody></table><h2 id="第四步-回-imgbed-填寫-google-drive-渠道" tabindex="-1">第四步：回 ImgBed 填寫 Google Drive 渠道 <a class="header-anchor" href="#第四步-回-imgbed-填寫-google-drive-渠道" aria-label="Permalink to &quot;第四步：回 ImgBed 填寫 Google Drive 渠道&quot;">​</a></h2><table tabindex="0"><thead><tr><th>頁面欄位</th><th>填寫內容</th></tr></thead><tbody><tr><td>渠道名稱</td><td>自己取，例如 <code>GoogleDrive主帳號</code></td></tr><tr><td>Client ID</td><td>Google Cloud 建立出的 Client ID</td></tr><tr><td>Client Secret</td><td>Google Cloud 建立出的 Client Secret</td></tr><tr><td>Refresh Token</td><td>先留空，下一步取得</td></tr><tr><td>根目錄</td><td>選填，預設 <code>imgbed</code></td></tr></tbody></table><p><img src="'+l+'" alt="把 Client 資訊貼回 ImgBed" loading="lazy"></p><h2 id="第五步-取得-refresh-token" tabindex="-1">第五步：取得 Refresh Token <a class="header-anchor" href="#第五步-取得-refresh-token" aria-label="Permalink to &quot;第五步：取得 Refresh Token&quot;">​</a></h2><ol><li>點「取得 Token」。</li><li>選擇要綁定的 Google 帳號。</li><li>依頁面提示完成授權。</li><li>成功後，回呼頁會顯示 <code>Refresh Token</code>。</li><li>複製它。</li><li>回到 ImgBed，貼到 <code>Refresh Token</code> 欄位。</li></ol><p><img src="'+o+`" alt="授權後複製 Refresh Token" loading="lazy"></p><p>如果之後換 Google 帳號、修改 Client，或舊授權失效，不用刪渠道，直接在編輯頁點「重新授權」即可。</p><h2 id="第六步-儲存渠道" tabindex="-1">第六步：儲存渠道 <a class="header-anchor" href="#第六步-儲存渠道" aria-label="Permalink to &quot;第六步：儲存渠道&quot;">​</a></h2><p>欄位填好後直接儲存。</p><h2 id="快速流程" tabindex="-1">快速流程 <a class="header-anchor" href="#快速流程" aria-label="Permalink to &quot;快速流程&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>登入 Google Cloud</span></span>
<span class="line"><span>-&gt; 建立或選擇專案</span></span>
<span class="line"><span>-&gt; 啟用 Google Drive API</span></span>
<span class="line"><span>-&gt; 設定 Google Auth Platform</span></span>
<span class="line"><span>-&gt; Audience 選 External 時，把自己的帳號加入 Test users</span></span>
<span class="line"><span>-&gt; 建立 Web application OAuth Client</span></span>
<span class="line"><span>-&gt; 回呼填 https://你的網域/api/oauth/google/callback</span></span>
<span class="line"><span>-&gt; 回 ImgBed 填 Client ID 和 Client Secret</span></span>
<span class="line"><span>-&gt; 點取得 Token</span></span>
<span class="line"><span>-&gt; Google 登入並授權</span></span>
<span class="line"><span>-&gt; 複製 Refresh Token</span></span>
<span class="line"><span>-&gt; 貼回 ImgBed 儲存</span></span>
<span class="line"><span>-&gt; 上傳測試圖片</span></span></code></pre></div>`,28)])])}const k=i(r,[["render",c]]);export{C as __pageData,k as default};
